// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check button add - field 部署コード -  enter not correct format number', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check button add - field 部署コード -  enter not correct format number', async function() {
    await driver.get("http://localhost:4200/admin-user/add-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-space-item > .ant-input")).click();
    await driver.findElement(By.xpath("//div[@id=\'department_code\']/div[2]/input")).sendKeys("scsc");
    await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.css(".ant-btn-default > span")).click();
    await driver.findElement(By.css("#department_code_help > .ant-form-item-explain-error")).click();
    assert(await driver.findElement(By.css("#department_code_help > .ant-form-item-explain-error")).getText() == "数字を入力してください。例: 1");
  });
});
